algorithm-divide.example_after:
def merge(left, right):
    result = []
    while left and right: result.append(left.pop(0) if left[0] <= right[0] else right.pop(0))
    return result + left + right
merged = merge([1, 4], [2, 3])
assert merged == [1, 2, 3, 4]
